106	func buildGraph(workingDir string, roots []string) (*Graph, error) {
107		files, err := findMarkdownFiles(workingDir, roots)
108		if err != nil {
109			return nil, err
110		}
111	
112		cleanRoot := filepath.Clean(workingDir)
113		documents := make(map[string]*Document)
114		pathToID := make(map[string]string)
115		warnings := []string{}
116		for _, filePath := range files {
117			doc, err := ParseDocument(filePath)
118			if err != nil {
119				if errors.Is(err, ErrNotDocGraphDocument) {
120					continue
121				}
122				warnings = append(warnings, fmt.Sprintf("%s: %v", filePath, err))
123				continue
124			}
125			if _, exists := documents[doc.ID]; exists {
126				warnings = append(warnings, fmt.Sprintf("duplicate document id %q in %q", doc.ID, filePath))
127				continue
128			}
129			doc.Path = relPath(cleanRoot, filePath)
130			documents[doc.ID] = doc
131			pathToID[doc.Path] = doc.ID
132		}
133	
134		g := &Graph{
135			RootDir:   cleanRoot,
136			Documents: documents,
137			PathToID:  pathToID,
138			Warnings:  warnings,
139		}
140		g.resolveBodyLinks()
141		g.buildDependents()
142		g.detectCycles()
143		g.applyConfigDefaults()
144		return g, nil
145	}
