147	func (g *Graph) applyConfigDefaults() {
148		for _, doc := range g.Documents {
149			doc.DependsOn = dedupeSortedStrings(doc.DependsOn)
150			doc.Inputs = dedupeSortedStrings(doc.Inputs)
151		}
152	}
