154	func (g *Graph) applyConfig(configs []GraphConfig) {
155		if len(configs) == 0 {
156			return
157		}
158	
159		idToPath := make(map[string]string)
160		cascade := make(map[string][]string)
161		for _, cfg := range configs {
162			for id, rawPath := range cfg.IDToPath {
163				if id == "" || rawPath == "" {
164					continue
165				}
166				idToPath[id] = filepath.Clean(filepath.Join(g.RootDir, rawPath))
167			}
168			for from, tos := range cfg.Cascade {
169				for _, to := range tos {
170					if from == "" || to == "" {
171						continue
172					}
173					cascade[from] = append(cascade[from], to)
174				}
175			}
176			if len(cfg.IDMap) > 0 {
177				for id, rawPath := range cfg.IDMap {
178					if id == "" || rawPath == "" {
179						continue
180					}
181					idToPath[id] = filepath.Clean(filepath.Join(g.RootDir, rawPath))
182				}
183			}
184			if len(cfg.Required) > 0 {
185				for _, id := range cfg.Required {
186					if _, ok := g.Documents[id]; !ok {
187						g.Warnings = append(g.Warnings, fmt.Sprintf("required root document %q not found", id))
188					}
189				}
190			}
191		}
192	
193		if len(idToPath) > 0 {
194			for id, path := range idToPath {
195				if _, ok := g.Documents[id]; ok {
196					continue
197				}
198				if _, err := os.Stat(path); err != nil {
199					g.Warnings = append(g.Warnings, fmt.Sprintf("id_to_path entry %q -> %q does not exist", id, path))
200					continue
201				}
202				doc, err := ParseDocument(path)
203				if err != nil {
204					if errors.Is(err, ErrNotDocGraphDocument) {
205						g.Warnings = append(g.Warnings, fmt.Sprintf("id_to_path entry %q -> %q is not a doc graph document", id, path))
206						continue
207					}
208					g.Warnings = append(g.Warnings, fmt.Sprintf("id_to_path entry %q -> %q could not be loaded: %v", id, path, err))
209					continue
210				}
211				if doc.ID != id {
212					g.Warnings = append(g.Warnings, fmt.Sprintf("id_to_path mismatch for %q: %q declares %q", id, path, doc.ID))
213					continue
214				}
215				g.Documents[id] = doc
216				doc.Path = relPath(g.RootDir, path)
217				g.PathToID[doc.Path] = id
218			}
219		}
220	
221		for from, toIDs := range cascade {
222			if _, ok := g.Documents[from]; !ok {
223				g.Warnings = append(g.Warnings, fmt.Sprintf("cascade rule refers to unknown dependency root %q", from))
224				continue
225			}
226			for _, to := range dedupeSortedStrings(toIDs) {
227				if to == "" {
228					continue
229				}
230				child, ok := g.Documents[to]
231				if !ok {
232					g.Warnings = append(g.Warnings, fmt.Sprintf("cascade rule refers to unknown target doc %q", to))
233					continue
234				}
235				if !containsString(child.DependsOn, from) {
236					child.DependsOn = append(child.DependsOn, from)
237				}
238			}
239		}
240	
241		for id := range g.Documents {
242			g.Documents[id].DependsOn = dedupeSortedStrings(g.Documents[id].DependsOn)
243		}
244		g.buildDependents()
245		g.detectCycles()
246	}
