248	func findMarkdownFiles(root string, roots []string) ([]string, error) {
249		targetDirs := []string{root}
250		if len(roots) > 0 {
251			targetDirs = roots
252		}
253	
254		files := []string{}
255		for _, base := range targetDirs {
256			cleanRoot := filepath.Clean(base)
257			err := filepath.Walk(cleanRoot, func(path string, info os.FileInfo, err error) error {
258				if err != nil {
259					return nil
260				}
261				if info == nil {
262					return nil
263				}
264				if info.IsDir() {
265					name := filepath.Base(path)
266					// Skip tool-managed directories. .claude is the Claude Code
267					// workspace (including throwaway copies under .claude/worktrees/);
268					// a worktrees/ directory at any depth is agent-scratch and must
269					// not be surfaced as canonical documents.
270					switch name {
271					case ".git", ".ddx", ".claude", "worktrees":
272						return filepath.SkipDir
273					}
274					return nil
275				}
276				if strings.HasPrefix(filepath.Base(path), ".") {
277					return nil
278				}
279				ext := strings.ToLower(filepath.Ext(path))
280				if ext != ".md" {
281					return nil
282				}
283				files = append(files, path)
284				return nil
285			})
286			if err != nil {
287				return nil, err
288			}
289		}
290		sort.Strings(files)
291		return files, nil
292	}
