294	// relPath returns filePath expressed relative to root. If filePath cannot be
295	// made relative (e.g. different volumes on Windows) the cleaned absolute path
296	// is returned. Callers treat the result as the canonical document path.
297	func relPath(root, filePath string) string {
298		clean := filepath.Clean(filePath)
299		if rel, err := filepath.Rel(root, clean); err == nil && !strings.HasPrefix(rel, ".."+string(filepath.Separator)) && rel != ".." {
300			return rel
301		}
302		return clean
303	}
