305	// absPath returns an absolute path for a document path stored on a Graph.
306	// Document paths are relative to g.RootDir; callers that need to touch the
307	// file on disk (read/write/git) must join with the root first.
308	func (g *Graph) absPath(docPath string) string {
309		if filepath.IsAbs(docPath) {
310			return docPath
311		}
312		return filepath.Join(g.RootDir, docPath)
313	}
