315	func ParseDocument(path string) (*Document, error) {
316		content, err := os.ReadFile(path)
317		if err != nil {
318			return nil, err
319		}
320	
321		frontmatter, body, err := ParseFrontmatter(content)
322		if err != nil {
323			return nil, err
324		}
325		if !frontmatter.HasFrontmatter || frontmatter.Doc.ID == "" {
326			return nil, fmt.Errorf("%w in %s", ErrNotDocGraphDocument, path)
327		}
328	
329		review := ReviewMetadata{
330			SelfHash:   frontmatter.Doc.Review.SelfHash,
331			ReviewedAt: frontmatter.Doc.Review.ReviewedAt,
332			Deps:       frontmatter.Doc.Review.Deps,
333		}
334		if review.Deps == nil {
335			review.Deps = map[string]string{}
336		}
337	
338		doc := &Document{
339			ID:            frontmatter.Doc.ID,
340			Title:         extractTitle([]byte(body)),
341			DependsOn:     dedupeSortedStrings(frontmatter.Doc.DependsOn),
342			Inputs:        dedupeSortedStrings(frontmatter.Doc.Inputs),
343			Review:        review,
344			ParkingLot:    frontmatter.Doc.ParkingLot,
345			Prompt:        frontmatter.Doc.Prompt,
346			ExecDef:       frontmatter.Doc.Exec,
347			body:          body,
348			bodyLinkTexts: extractBodyLinks(body),
349		}
350		if frontmatter.Raw != nil {
351			doc.frontmatter = frontmatter.Raw
352		}
353	
354		contentHash, err := HashDocument(frontmatter.Raw, body)
355		if err != nil {
356			return nil, err
357		}
358		doc.contentHash = contentHash
359		return doc, nil
360	}
