362	func (g *Graph) buildDependents() {
363		g.Dependents = make(map[string][]string)
364		for id := range g.Documents {
365			g.Dependents[id] = g.Dependents[id][:0]
366		}
367		for id, doc := range g.Documents {
368			for _, dep := range doc.DependsOn {
369				if _, ok := g.Documents[dep]; !ok {
370					continue
371				}
372				if containsString(g.Dependents[dep], id) {
373					continue
374				}
375				g.Dependents[dep] = append(g.Dependents[dep], id)
376			}
377		}
378		for id := range g.Dependents {
379			g.Dependents[id] = dedupeSortedStrings(g.Dependents[id])
380		}
381		for id, doc := range g.Documents {
382			doc.Dependents = append([]string{}, g.Dependents[id]...)
383		}
384	}
