386	func (g *Graph) detectCycles() {
387		index := 0
388		indexes := map[string]int{}
389		lowlinks := map[string]int{}
390		onStack := map[string]bool{}
391		stack := []string{}
392		warned := map[string]struct{}{}
393		var visit func(string)
394	
395		visit = func(id string) {
396			indexes[id] = index
397			lowlinks[id] = index
398			index++
399			stack = append(stack, id)
400			onStack[id] = true
401	
402			node := g.Documents[id]
403			for _, dep := range node.DependsOn {
404				if _, ok := g.Documents[dep]; !ok {
405					continue
406				}
407				if _, ok := indexes[dep]; !ok {
408					visit(dep)
409					if lowlinks[dep] < lowlinks[id] {
410						lowlinks[id] = lowlinks[dep]
411					}
412				} else if onStack[dep] {
413					if indexes[dep] < lowlinks[id] {
414						lowlinks[id] = indexes[dep]
415					}
416				}
417			}
418	
419			if lowlinks[id] == indexes[id] {
420				cycle := []string{}
421				for {
422					last := stack[len(stack)-1]
423					stack = stack[:len(stack)-1]
424					onStack[last] = false
425					cycle = append(cycle, last)
426					if last == id {
427						break
428					}
429				}
430				if len(cycle) > 1 {
431					warnKey := cycleKey(cycle)
432					if _, done := warned[warnKey]; done {
433						return
434					}
435					warned[warnKey] = struct{}{}
436					label := renderCycle(cycle)
437					g.Warnings = append(g.Warnings, fmt.Sprintf("cycle detected: %s", label))
438				} else {
439					parent := g.Documents[id]
440					selfDepends := containsString(parent.DependsOn, id)
441					if selfDepends {
442						label := fmt.Sprintf("%s -> %s", id, id)
443						g.Warnings = append(g.Warnings, fmt.Sprintf("cycle detected: %s", label))
444					}
445				}
446			}
447		}
448	
449		for id := range g.Documents {
450			if _, ok := indexes[id]; !ok {
451				visit(id)
452			}
453		}
454	
455		sort.Strings(g.Warnings)
456	}
