458	func cycleKey(ids []string) string {
459		if len(ids) == 0 {
460			return ""
461		}
462		copyIDs := append([]string(nil), ids...)
463		sort.Strings(copyIDs)
464		return strings.Join(copyIDs, "::")
465	}
466	
467	func renderCycle(ids []string) string {
468		if len(ids) == 0 {
469			return ""
470		}
471		copyIDs := append([]string(nil), ids...)
472		sort.Strings(copyIDs)
473		start := copyIDs[0]
474		return start + " -> " + strings.Join(copyIDs[1:], " -> ") + " -> " + start
475	}
