477	func (g *Graph) StaleDocs() []StaleReason {
478		if len(g.Documents) == 0 {
479			return nil
480		}
481	
482		direct := map[string][]string{}
483		for id := range g.Documents {
484			doc, ok := g.Documents[id]
485			if !ok || doc.ParkingLot {
486				continue
487			}
488			reasons := staleReasonsForDocument(g, doc)
489			if len(reasons) > 0 {
490				direct[id] = reasons
491			}
492		}
493	
494		final := map[string][]string{}
495		queue := []string{}
496		for id, reasons := range direct {
497			final[id] = append([]string(nil), reasons...)
498			queue = append(queue, id)
499		}
500	
501		seen := map[string]struct{}{}
502		for _, id := range queue {
503			seen[id] = struct{}{}
504		}
505		for i := 0; i < len(queue); i++ {
506			u := queue[i]
507			for _, dep := range g.Dependents[u] {
508				child, ok := g.Documents[dep]
509				if !ok || child.ParkingLot {
510					continue
511				}
512				if _, done := seen[dep]; done {
513					continue
514				}
515				seen[dep] = struct{}{}
516				final[dep] = []string{"upstream stale dependency"}
517				queue = append(queue, dep)
518			}
519		}
520	
521		ids := make([]string, 0, len(final))
522		for id := range final {
523			ids = append(ids, id)
524		}
525		sort.Strings(ids)
526		result := make([]StaleReason, 0, len(ids))
527		for _, id := range ids {
528			doc := g.Documents[id]
529			reason := StaleReason{ID: id, Path: doc.Path, Reasons: final[id]}
530			sort.Strings(reason.Reasons)
531			result = append(result, reason)
532		}
533		return result
534	}
