536	func staleReasonsForDocument(g *Graph, doc *Document) []string {
537		reasons := []string{}
538		for _, depID := range doc.DependsOn {
539			depDoc, ok := g.Documents[depID]
540			if !ok {
541				reasons = append(reasons, fmt.Sprintf("missing dependency: %s", depID))
542				continue
543			}
544			expected := doc.Review.Deps[depID]
545			if expected == "" {
546				reasons = append(reasons, fmt.Sprintf("missing review hash for dependency: %s", depID))
547				continue
548			}
549			if expected != depDoc.contentHash {
550				reasons = append(reasons, fmt.Sprintf("dependency changed: %s", depID))
551			}
552		}
553		return dedupeSortedStrings(reasons)
554	}
