556	func (g *Graph) StaleReasonForID(id string) (StaleReason, bool) {
557		stale := g.StaleDocs()
558		for _, entry := range stale {
559			if entry.ID == id {
560				return entry, true
561			}
562		}
563		doc, ok := g.Documents[id]
564		if !ok {
565			return StaleReason{}, false
566		}
567		return StaleReason{ID: id, Path: doc.Path, Reasons: nil}, true
568	}
