590	func (g *Graph) ResolvePathsToIDs(targets []string) ([]string, error) {
591		ids := make([]string, 0, len(targets))
592		seen := map[string]struct{}{}
593		for _, target := range targets {
594			if target == "" {
595				continue
596			}
597			if id, ok := g.Documents[target]; ok {
598				if _, done := seen[id.ID]; !done {
599					seen[id.ID] = struct{}{}
600					ids = append(ids, id.ID)
601				}
602				continue
603			}
604			resolved := target
605			if !filepath.IsAbs(resolved) {
606				resolved = filepath.Join(g.RootDir, resolved)
607			}
608			resolved = filepath.Clean(resolved)
609			lookupKey := relPath(g.RootDir, resolved)
610			if id, ok := g.PathToID[lookupKey]; ok {
611				if _, done := seen[id]; !done {
612					seen[id] = struct{}{}
613					ids = append(ids, id)
614				}
615				continue
616			}
617			if info, err := os.Stat(resolved); err == nil && info.IsDir() {
618				err := filepath.Walk(resolved, func(path string, info os.FileInfo, err error) error {
619					if err != nil {
620						return nil
621					}
622					if info.IsDir() {
623						switch info.Name() {
624						case ".git", ".ddx", ".claude", "worktrees":
625							return filepath.SkipDir
626						}
627						return nil
628					}
629					if strings.EqualFold(filepath.Ext(path), ".md") {
630						walkKey := relPath(g.RootDir, path)
631						if id, ok := g.PathToID[walkKey]; ok {
632							if _, done := seen[id]; !done {
633								seen[id] = struct{}{}
634								ids = append(ids, id)
635							}
636						}
637					}
638					return nil
639				})
640				if err != nil {
641					return nil, err
642				}
643				continue
644			}
645			return nil, fmt.Errorf("cannot resolve target %q", target)
646		}
647		if len(ids) == 0 {
648			return nil, fmt.Errorf("no matching targets")
649		}
650		return dedupeSortedStrings(ids), nil
651	}
