653	func (g *Graph) Stamp(targets []string, now time.Time) ([]string, []string, error) {
654		docIDs, err := g.ResolvePathsToIDs(targets)
655		if err != nil {
656			return nil, nil, err
657		}
658	
659		stamped := make([]string, 0, len(docIDs))
660		warnings := []string{}
661		for _, id := range docIDs {
662			doc, ok := g.Documents[id]
663			if !ok {
664				warnings = append(warnings, fmt.Sprintf("document %q not found", id))
665				continue
666			}
667			if doc.frontmatter == nil {
668				warnings = append(warnings, fmt.Sprintf("document %q missing frontmatter", id))
669				continue
670			}
671			review := ReviewMetadata{
672				SelfHash:   doc.contentHash,
673				ReviewedAt: now.UTC().Format(time.RFC3339),
674				Deps:       map[string]string{},
675			}
676			for _, depID := range doc.DependsOn {
677				if dep, ok := g.Documents[depID]; ok {
678					review.Deps[depID] = dep.contentHash
679				}
680			}
681			if review.Deps == nil {
682				review.Deps = map[string]string{}
683			}
684			reviewForWrite := DocReview(review)
685			err := SetReview(doc.frontmatter, reviewForWrite)
686			if err != nil {
687				return stamped, warnings, err
688			}
689			frontmatterText, err := EncodeFrontmatter(doc.frontmatter)
690			if err != nil {
691				return stamped, warnings, err
692			}
693			updated := frontmatterSeparator + "\n" + frontmatterText + "\n" + frontmatterSeparator + "\n" + doc.body
694			if err := os.WriteFile(g.absPath(doc.Path), []byte(updated), 0644); err != nil {
695				return stamped, warnings, err
696			}
697			if doc.Review.ReviewedAt == "" || doc.Review.SelfHash != review.SelfHash {
698				doc.Review = review
699			}
700			stamped = append(stamped, id)
701		}
702		sort.Strings(stamped)
703		return stamped, warnings, nil
704	}
