723	func (g *Graph) AllNodesForOutput() []Document {
724		ids := g.All()
725		out := make([]Document, 0, len(ids))
726		for _, id := range ids {
727			doc := g.Documents[id]
728			if doc == nil {
729				continue
730			}
731			out = append(out, *doc)
