736	func extractTitle(body []byte) string {
737		for _, line := range strings.Split(normalizeNewlines(string(body)), "\n") {
738			trimmed := strings.TrimSpace(line)
739			if strings.HasPrefix(trimmed, "# ") {
740				return strings.TrimSpace(strings.TrimPrefix(trimmed, "# "))
741			}
742		}
743		return ""
744	}
745	
746	func dedupeSortedStrings(values []string) []string {
747		seen := map[string]struct{}{}
748		out := make([]string, 0, len(values))
749		for _, value := range values {
750			v := strings.TrimSpace(value)
751			if v == "" {
752				continue
753			}
754			if _, ok := seen[v]; ok {
755				continue
756			}
757			seen[v] = struct{}{}
758			out = append(out, v)
759		}
760		sort.Strings(out)
761		return out
762	}
763	
764	func containsString(values []string, target string) bool {
765		for _, value := range values {
766			if value == target {
767				return true
768			}
769		}
770		return false
771	}
772	
773	var bodyLinkPattern = regexp.MustCompile(`\[\[([^\[\]]+)\]\]`)
774	
775	// extractBodyLinks returns the raw text inside every [[...]] span in body.
776	// Nested or malformed brackets are skipped.
777	func extractBodyLinks(body string) []string {
778		matches := bodyLinkPattern.FindAllStringSubmatch(body, -1)
779		if len(matches) == 0 {
780			return nil
781		}
782		out := make([]string, 0, len(matches))
783		for _, m := range matches {
784			text := strings.TrimSpace(m[1])
785			if text != "" {
786				out = append(out, text)
787			}
788		}
789		return out
790	}
791	
792	// slugifyID converts a wikilink label into a lowercase-hyphen slug suitable
793	// for ID matching. Dots are preserved (dotted IDs). Spaces and underscores
794	// become hyphens. Other non-alphanumeric characters are dropped.
795	func slugifyID(text string) string {
796		var b strings.Builder
797		prevHyphen := false
798		for _, r := range strings.ToLower(text) {
799			switch {
800			case unicode.IsLetter(r) || unicode.IsDigit(r) || r == '.':
801				b.WriteRune(r)
802				prevHyphen = false
803			case r == '-' || r == '_' || unicode.IsSpace(r):
804				if !prevHyphen && b.Len() > 0 {
805					b.WriteByte('-')
806					prevHyphen = true
807				}
808			}
809		}
810		result := b.String()
811		return strings.TrimRight(result, "-")
812	}
813	
814	// resolveBodyLinks merges body [[ID]] references into each document's DependsOn.
815	func (g *Graph) resolveBodyLinks() {
816		for _, doc := range g.Documents {
817			if len(doc.bodyLinkTexts) == 0 {
818				continue
819			}
820			for _, text := range doc.bodyLinkTexts {
821				resolved := resolveBodyLinkText(text, g.Documents)
822				if resolved == "" || resolved == doc.ID {
823					continue
824				}
825				if !containsString(doc.DependsOn, resolved) {
826					doc.DependsOn = append(doc.DependsOn, resolved)
827				}
828			}
829			doc.DependsOn = dedupeSortedStrings(doc.DependsOn)
830		}
831	}
832	
833	// resolveBodyLinkText tries to resolve a raw wikilink text to a document ID.
834	// Resolution order: exact match, then slug match.
835	func resolveBodyLinkText(text string, docs map[string]*Document) string {
836		if _, ok := docs[text]; ok {
837			return text
838		}
839		slug := slugifyID(text)
840		if slug != text {
841			if _, ok := docs[slug]; ok {
842				return slug
843			}
844		}
845		return ""
846	}
847	
848	func LoadGraphConfigs(workingDir string) ([]GraphConfig, error) {
849		cfgDir := filepath.Join(workingDir, ".ddx", "graphs")
850		entries, err := os.ReadDir(cfgDir)
851		if err != nil {
852			if os.IsNotExist(err) {
853				return nil, nil
854			}
855			return nil, err
856		}
857	
858		configs := []GraphConfig{}
859		for _, entry := range entries {
860			if entry.IsDir() {
861				continue
862			}
863			ext := strings.ToLower(filepath.Ext(entry.Name()))
864			if ext != ".yml" && ext != ".yaml" {
865				continue
866			}
867			cfgPath := filepath.Join(cfgDir, entry.Name())
868			raw, err := os.ReadFile(cfgPath)
869			if err != nil {
870				return nil, fmt.Errorf("read graph config %q: %w", cfgPath, err)
871			}
872			var cfg GraphConfig
873			if err := yaml.Unmarshal(raw, &cfg); err != nil {
874				return nil, fmt.Errorf("parse graph config %q: %w", cfgPath, err)
875			}
876			configs = append(configs, cfg)
877		}
878		sort.Slice(configs, func(i, j int) bool {
879			return len(configs[i].Roots) > len(configs[j].Roots)
880		})
881		return configs, nil
882	}
