16	// DocumentByPath is the resolver for the documentByPath field.
17	// It reads the document at the given path (relative to the docgraph root or
18	// library) and returns its metadata plus raw file content.
19	func (r *queryResolver) DocumentByPath(ctx context.Context, path string) (*Document, error) {
20		if path == "" {
21			return nil, fmt.Errorf("path is required")
22		}
23	
24		cleaned := filepath.Clean(path)
25		if strings.Contains(cleaned, "..") {
26			return nil, fmt.Errorf("invalid path")
27		}
28		// Legacy clients may emit absolute filesystem paths (bead ddx-12cae4dd)
29		// produced before doc.Path was normalised. Reject them — any real document
30		// resolved through the graph uses a relative path.
31		if filepath.IsAbs(cleaned) {
32			return nil, nil
33		}
34	
35		// Prefer the docgraph-tracked location: the documents list surfaces files
36		// walked under workingDir, so the detail view must read from the same root
37		// (otherwise the URL for a valid list entry 404s).
38		if graph, graphErr := docgraph.BuildGraphWithConfig(r.WorkingDir); graphErr == nil {
39			if id, ok := graph.PathToID[cleaned]; ok {
40				if d, ok := graph.Documents[id]; ok {
41					absPath := d.Path
42					if !filepath.IsAbs(absPath) {
43						absPath = filepath.Join(graph.RootDir, absPath)
44					}
45					if data, readErr := os.ReadFile(absPath); readErr == nil {
46						content := string(data)
47						doc := docToGQL(*d)
48						doc.Content = &content
49						return doc, nil
50					}
51				}
52			}
53		}
54	
55		// Fall back to the configured library path so documents created via the
56		// documentWrite mutation (which target the library) remain readable even
57		// when they have no DDx frontmatter and so do not appear in the graph.
58		cfg, err := config.LoadWithWorkingDir(r.WorkingDir)
59		if err != nil {
60			return nil, fmt.Errorf("loading config: %w", err)
61		}
62		if cfg.Library == nil || cfg.Library.Path == "" {
63			return nil, nil
64		}
65		libPath := cfg.Library.Path
66		if !filepath.IsAbs(libPath) {
67			libPath = filepath.Join(r.WorkingDir, libPath)
68		}
69	
70		fullPath := filepath.Join(libPath, cleaned)
71		data, err := os.ReadFile(fullPath)
72		if err != nil {
73			return nil, nil // not found → null
74		}
75		content := string(data)
76	
77		return &Document{
78			ID:         cleaned,
79			Path:       cleaned,
80			DependsOn:  []string{},
81			Inputs:     []string{},
82			Dependents: []string{},
83			Content:    &content,
84		}, nil
85	}
