87	// Documents is the resolver for the documents field with Relay cursor pagination.
88	func (r *queryResolver) Documents(ctx context.Context, first *int, after *string, last *int, before *string, typeArg *string) (*DocumentConnection, error) {
89		graph, err := docgraph.BuildGraphWithConfig(r.WorkingDir)
90		if err != nil {
91			return nil, fmt.Errorf("building document graph: %w", err)
92		}
93	
94		docs := graph.AllNodesForOutput()
95		sort.Slice(docs, func(i, j int) bool { return docs[i].ID < docs[j].ID })
96	
97		// Apply optional type filter by path component.
98		if typeArg != nil && *typeArg != "" {
99			filtered := docs[:0]
100			for _, d := range docs {
101				if strings.Contains(d.Path, string([]rune{'/'})+*typeArg+string([]rune{'/'})) ||
102					strings.HasPrefix(d.Path, *typeArg+string([]rune{'/'})) {
103					filtered = append(filtered, d)
104				}
105			}
106			docs = filtered
107		}
108	
109		all := make([]*DocumentEdge, len(docs))
110		for i, d := range docs {
111			all[i] = &DocumentEdge{
112				Node:   docToGQL(d),
113				Cursor: encodeStableCursor(d.ID),
114			}
115		}
116	
117		startIdx := 0
118		if after != nil {
119			if afterID, ok := decodeStableCursor(*after); ok {
120				for i, e := range all {
121					if e.Node.ID == afterID {
122						startIdx = i + 1
123						break
124					}
125				}
126			}
127		}
128		endIdx := len(all)
129		if before != nil {
130			if beforeID, ok := decodeStableCursor(*before); ok {
131				for i, e := range all {
132					if e.Node.ID == beforeID {
133						endIdx = i
134						break
135					}
136				}
137			}
138		}
139		if startIdx > endIdx {
140			startIdx = endIdx
141		}
142	
143		slice := all[startIdx:endIdx]
144		if first != nil && *first >= 0 && *first < len(slice) {
145			slice = slice[:*first]
146		}
147		if last != nil && *last >= 0 && *last < len(slice) {
148			slice = slice[len(slice)-*last:]
149		}
150	
151		pageInfo := &PageInfo{
152			HasPreviousPage: startIdx > 0,
153			HasNextPage:     endIdx < len(all),
154		}
155		if len(slice) > 0 {
156			pageInfo.StartCursor = &slice[0].Cursor
157			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
158		}
159	
160		return &DocumentConnection{
161			Edges:      slice,
162			PageInfo:   pageInfo,
163			TotalCount: len(all),
164		}, nil
165	}
166	
167	// DocGraph is the resolver for the docGraph field.
168	func (r *queryResolver) DocGraph(ctx context.Context) (*DocGraph, error) {
169		graph, err := docgraph.BuildGraphWithConfig(r.WorkingDir)
170		if err != nil {
171			return nil, fmt.Errorf("building document graph: %w", err)
172		}
173	
174		docs := graph.AllNodesForOutput()
175		sort.Slice(docs, func(i, j int) bool { return docs[i].ID < docs[j].ID })
176		gqlDocs := make([]*Document, len(docs))
177		for i, d := range docs {
178			gqlDocs[i] = docToGQL(d)
179		}
180	
181		pathToIDJSON, err := json.Marshal(graph.PathToID)
182		if err != nil {
183			return nil, fmt.Errorf("serializing pathToId: %w", err)
184		}
185		dependentsJSON, err := json.Marshal(graph.Dependents)
186		if err != nil {
187			return nil, fmt.Errorf("serializing dependents: %w", err)
188		}
189	
190		warnings := graph.Warnings
191		if warnings == nil {
192			warnings = []string{}
193		}
194	
195		return &DocGraph{
196			RootDir:    graph.RootDir,
197			Documents:  gqlDocs,
198			PathToID:   string(pathToIDJSON),
199			Dependents: string(dependentsJSON),
200			Warnings:   warnings,
201		}, nil
202	}
203	
204	// docToGQL converts a docgraph.Document to the GraphQL Document model.
205	func docToGQL(d docgraph.Document) *Document {
206		doc := &Document{
207			ID:         d.ID,
208			Path:       d.Path,
209			Title:      d.Title,
210			DependsOn:  d.DependsOn,
211			Inputs:     d.Inputs,
212			Dependents: d.Dependents,
213			ParkingLot: d.ParkingLot,
214		}
215		if doc.DependsOn == nil {
216			doc.DependsOn = []string{}
217		}
218		if doc.Inputs == nil {
219			doc.Inputs = []string{}
220		}
221		if doc.Dependents == nil {
222			doc.Dependents = []string{}
223		}
224		if d.Prompt != "" {
225			p := d.Prompt
226			doc.Prompt = &p
227		}
228		if d.Review.ReviewedAt != "" || d.Review.SelfHash != "" {
229			depsJSON, _ := json.Marshal(d.Review.Deps)
230			doc.Review = &DocumentReview{
231				SelfHash:   d.Review.SelfHash,
232				Deps:       string(depsJSON),
233				ReviewedAt: d.Review.ReviewedAt,
234			}
235		}
236		if d.ExecDef != nil {
237			active := d.ExecDef.Active
238			required := d.ExecDef.Required
239			graphSource := true
240			doc.ExecDef = &DocumentExecDef{
241				ArtifactIds: d.ExecDef.ArtifactIDs,
242				Active:      &active,
243				Required:    &required,
244				GraphSource: &graphSource,
245			}
246		}
247		return doc
248	}
