569	// TestBuildGraph_ExcludesClaudeWorktreesAndStoresRelativePaths verifies the two
570	// defects fixed alongside the bead ddx-12cae4dd:
571	//
572	//  1. Agent worktree copies checked out under .claude/worktrees/ must not be
573	//     surfaced by the documents graph, even when they contain markdown files
574	//     with valid DDx frontmatter that would otherwise duplicate canonical
575	//     docs/ entries.
576	//  2. Document paths stored on the graph must be relative to the working
577	//     directory. Leaking absolute filesystem paths produced malformed URLs
578	//     (leading double slashes) in the web UI documents view.
579	func TestBuildGraph_ExcludesClaudeWorktreesAndStoresRelativePaths(t *testing.T) {
580		root := setupTestRepo(t, map[string]string{
581			"docs/foo.md":                           "---\nddx:\n  id: foo\n---\n# Canonical Foo\n",
582			".claude/worktrees/agent-x/docs/foo.md": "---\nddx:\n  id: foo.dup\n---\n# Shadow Foo\n",
583			".claude/worktrees/agent-x/README.md":   "---\nddx:\n  id: shadow.readme\n---\n# Shadow Readme\n",
584		})
585	
586		graph, err := BuildGraph(root)
587		if err != nil {
588			t.Fatal(err)
589		}
590	
591		if graph.Documents["foo"] == nil {
592			t.Fatal("expected canonical docs/foo.md document in graph")
593		}
594		if graph.Documents["foo.dup"] != nil {
595			t.Error(".claude/worktrees shadow copy should be excluded")
596		}
597		if graph.Documents["shadow.readme"] != nil {
598			t.Error(".claude/worktrees README.md should be excluded")
599		}
600	
601		for id, doc := range graph.Documents {
602			if filepath.IsAbs(doc.Path) {
603				t.Errorf("document %q has absolute path %q, want path relative to working dir", id, doc.Path)
604			}
605			if strings.Contains(filepath.ToSlash(doc.Path), ".claude/") {
606				t.Errorf("document %q path %q contains .claude/ (worktrees must be skipped)", id, doc.Path)
607			}
608		}
609		for key := range graph.PathToID {
610			if filepath.IsAbs(key) {
611				t.Errorf("PathToID key %q is absolute, want relative", key)
612			}
613			if strings.Contains(filepath.ToSlash(key), ".claude/") {
614				t.Errorf("PathToID key %q contains .claude/", key)
615			}
616		}
617	
618		if doc := graph.Documents["foo"]; doc != nil {
619			want := filepath.FromSlash("docs/foo.md")
620			if doc.Path != want {
621				t.Errorf("got doc.Path %q, want %q", doc.Path, want)
622			}
623		}
624	}
