152				} else {
153					if len(args) == 0 {
154						return fmt.Errorf("provide document paths or use --all")
155					}
156					targets = args
157				}
158	
159				stamped, warnings, err := graph.Stamp(targets, time.Now())
160				if err != nil {
161					return err
162				}
163	
164				// Load config for auto-commit settings (best-effort; ignore errors).
165				var acCfg internalgit.AutoCommitConfig
166				if cfg, cfgErr := config.LoadWithWorkingDir(f.docRoot()); cfgErr == nil && cfg.Git != nil {
167					acCfg.AutoCommit = cfg.Git.AutoCommit
168					acCfg.CommitPrefix = cfg.Git.CommitPrefix
169				}
170	
171				for _, w := range warnings {
172					fmt.Fprintf(cmd.ErrOrStderr(), "warning: %s\n", w)
173				}
174				for _, id := range stamped {
175					doc, ok := graph.Documents[id]
176					path := id
177					if ok {
178						path = doc.Path
179					}
180					fmt.Fprintf(cmd.OutOrStdout(), "stamped %s\n", path)
181					autoCommitPath := path
182					if ok && !filepath.IsAbs(autoCommitPath) {
183						autoCommitPath = filepath.Join(graph.RootDir, autoCommitPath)
184					}
185					if _, acErr := internalgit.AutoCommit(autoCommitPath, id, "stamp reviewed", acCfg); acErr != nil {
186						fmt.Fprintf(cmd.ErrOrStderr(), "warning: auto-commit failed for %s: %v\n", path, acErr)
187					}
188				}
189				return nil
190			},
