271	func (f *CommandFactory) newDocMigrateCommand() *cobra.Command {
272		cmd := &cobra.Command{
273			Use:   "migrate [path]",
274			Short: "Convert legacy `dun:` frontmatter to `ddx:`",
275			Long: `Migrate markdown documents by replacing legacy ` + "`" + `dun:` + "`" + ` frontmatter namespaces with ` + "`" + `ddx:` + "`" + `.
276	
277	Examples:
278	  ddx doc migrate
279	  ddx doc migrate docs/`,
280			Args: cobra.MaximumNArgs(1),
281			RunE: func(cmd *cobra.Command, args []string) error {
282				target := f.docRoot()
283				if len(args) == 1 {
284					target = args[0]
285				}
286	
287				_, err := os.Stat(target)
288				if err != nil {
289					return fmt.Errorf("path not found: %s", target)
290				}
291	
292				convertCount := 0
293				skipCount := 0
294	
295				err = filepath.WalkDir(target, func(path string, d fs.DirEntry, walkErr error) error {
296					if walkErr != nil {
297						return walkErr
298					}
299					if d.IsDir() {
300						return nil
301					}
302					if !strings.HasSuffix(d.Name(), ".md") {
303						return nil
304					}
305	
306					content, readErr := os.ReadFile(path)
307					if readErr != nil {
308						return readErr
309					}
310	
311					fm, body, parseErr := docgraph.ParseFrontmatter(content)
312					if parseErr != nil || !fm.HasFrontmatter || fm.Namespace != "dun" {
313						if parseErr != nil {
314							return parseErr
315						}
316						skipCount++
317						return nil
318					}
319	
320					didMigrate := docgraph.MigrateLegacyDunFrontmatter(fm.Raw)
321					if !didMigrate {
322						skipCount++
323						return nil
324					}
325	
326					frontmatterText, encodeErr := docgraph.EncodeFrontmatter(fm.Raw)
327					if encodeErr != nil {
328						return encodeErr
329					}
330	
331					updated := []byte(fmt.Sprintf("---\n%s\n---\n%s", frontmatterText, body))
332					if err := os.WriteFile(path, updated, 0644); err != nil {
333						return err
334					}
335					convertCount++
336					return nil
337				})
338				if err != nil {
339					return err
340				}
341	
342				fmt.Fprintf(cmd.OutOrStdout(), "migrated %d files, skipped %d files\n", convertCount, skipCount)
343				return nil
344			},
345		}
346		return cmd
347	}
