475	func (f *CommandFactory) newDocHistoryCommand() *cobra.Command {
476		cmd := &cobra.Command{
477			Use:   "history <id>",
478			Short: "Show commit log for an artifact",
479			Args:  cobra.ExactArgs(1),
480			RunE: func(cmd *cobra.Command, args []string) error {
481				graph, err := f.buildDocGraph()
482				if err != nil {
483					return err
484				}
485				doc, ok := graph.Documents[args[0]]
486				if !ok {
487					return fmt.Errorf("document not found: %s", args[0])
488				}
489	
490				since, _ := cmd.Flags().GetString("since")
491				asJSON, _ := cmd.Flags().GetBool("json")
492	
493				gitArgs := []string{"log", "--follow", "--format=%H\t%ai\t%an\t%s"}
494				if since != "" {
495					gitArgs = append(gitArgs, since+"..HEAD")
496				}
497				gitArgs = append(gitArgs, "--", doc.Path)
498	
499				gitCmd := exec.Command("git", gitArgs...)
500				gitCmd.Dir = f.docRoot()
501				out, gitErr := gitCmd.Output()
502				if gitErr != nil {
503					if exitErr, ok2 := gitErr.(*exec.ExitError); ok2 {
504						if strings.Contains(string(exitErr.Stderr), "not a git repository") {
505							return fmt.Errorf("not a git repository")
506						}
507					}
508					return fmt.Errorf("git log failed: %w", gitErr)
509				}
510	
511				type commitEntry struct {
512					Hash    string `json:"hash"`
513					Date    string `json:"date"`
514					Author  string `json:"author"`
515					Message string `json:"message"`
516				}
517	
518				lines := strings.Split(strings.TrimRight(string(out), "\n"), "\n")
519				entries := make([]commitEntry, 0, len(lines))
520				for _, line := range lines {
521					if line == "" {
522						continue
523					}
524					parts := strings.SplitN(line, "\t", 4)
525					if len(parts) < 4 {
526						continue
527					}
528					hash := parts[0]
529					if len(hash) > 7 {
530						hash = hash[:7]
531					}
532					date := parts[1]
533					if len(date) > 10 {
534						date = date[:10]
535					}
536					entries = append(entries, commitEntry{
537						Hash:    hash,
538						Date:    date,
539						Author:  parts[2],
540						Message: parts[3],
541					})
542				}
543	
544				if asJSON {
545					enc := json.NewEncoder(cmd.OutOrStdout())
546					enc.SetIndent("", "  ")
547					return enc.Encode(entries)
548				}
549	
550				if len(entries) == 0 {
551					fmt.Fprintln(cmd.OutOrStdout(), "No commits found.")
552					return nil
553				}
554				for _, e := range entries {
555					fmt.Fprintf(cmd.OutOrStdout(), "%s  %s  %s  %s\n", e.Hash, e.Date, e.Author, e.Message)
556				}
557				return nil
558			},
559		}
560		cmd.Flags().String("since", "", "Show commits since this ref (e.g. HEAD~10)")
561		cmd.Flags().Bool("json", false, "Output as JSON")
562		return cmd
563	}
