612	func (f *CommandFactory) newDocChangedCommand() *cobra.Command {
613		cmd := &cobra.Command{
614			Use:   "changed",
615			Short: "List artifacts changed since a git ref",
616			Args:  cobra.NoArgs,
617			RunE: func(cmd *cobra.Command, args []string) error {
618				since, _ := cmd.Flags().GetString("since")
619				if since == "" {
620					since = "HEAD~5"
621				}
622				asJSON, _ := cmd.Flags().GetBool("json")
623	
624				out, gitErr := exec.Command("git", "diff", "--name-status", since, "HEAD").Output()
625				if gitErr != nil {
626					if exitErr, ok := gitErr.(*exec.ExitError); ok {
627						if strings.Contains(string(exitErr.Stderr), "not a git repository") {
628							return fmt.Errorf("not a git repository")
629						}
630					}
631					return fmt.Errorf("git diff failed: %w", gitErr)
632				}
633	
634				rootOut, gitErr := exec.Command("git", "rev-parse", "--show-toplevel").Output()
635				if gitErr != nil {
636					return fmt.Errorf("could not determine git root: %w", gitErr)
637				}
638				repoRoot := strings.TrimRight(string(rootOut), "\n")
639	
640				type changedEntry struct {
641					ID         string `json:"id"`
642					Path       string `json:"path"`
643					ChangeType string `json:"change_type"`
644				}
645	
646				graph, err := f.buildDocGraph()
647				if err != nil {
648					return err
649				}
650	
651				var entries []changedEntry
652				for _, line := range strings.Split(strings.TrimRight(string(out), "\n"), "\n") {
653					if line == "" {
654						continue
655					}
656					fields := strings.Fields(line)
657					if len(fields) < 2 {
658						continue
659					}
660					statusCode := fields[0]
661					relPath := fields[len(fields)-1]
662	
663					if !strings.HasSuffix(relPath, ".md") {
664						continue
665					}
666	
667					absPath := filepath.Join(repoRoot, relPath)
668					cleanPath := filepath.Clean(absPath)
669					graphKey := cleanPath
670					if rel, relErr := filepath.Rel(graph.RootDir, cleanPath); relErr == nil {
671						graphKey = rel
672					}
673	
674					var changeType string
675					switch {
676					case strings.HasPrefix(statusCode, "A"):
677						changeType = "added"
678					case strings.HasPrefix(statusCode, "D"):
679						changeType = "deleted"
680					default:
681						changeType = "modified"
682					}
683	
684					if changeType == "deleted" {
685						if id, ok := graph.PathToID[graphKey]; ok {
686							entries = append(entries, changedEntry{ID: id, Path: relPath, ChangeType: changeType})
687						}
688						continue
689					}
690	
691					if id, ok := graph.PathToID[graphKey]; ok {
692						entries = append(entries, changedEntry{ID: id, Path: relPath, ChangeType: changeType})
693						continue
694					}
695	
696					content, readErr := os.ReadFile(absPath)
697					if readErr != nil {
698						continue
699					}
700					fm, _, parseErr := docgraph.ParseFrontmatter(content)
701					if parseErr != nil || !fm.HasFrontmatter || fm.Doc.ID == "" {
702						continue
703					}
704					entries = append(entries, changedEntry{ID: fm.Doc.ID, Path: relPath, ChangeType: changeType})
705				}
706	
707				if asJSON {
708					enc := json.NewEncoder(cmd.OutOrStdout())
709					enc.SetIndent("", "  ")
